 59→/** Module names that spawn subprocesses — require() calls to these are flagged. */
 60→const SUBPROCESS_MODULES = new Set([
 61→  "child_process", "node:child_process",
 62→]);
 63→
 64→/** Symbols within child_process that spawn subprocesses. */
 65→const SUBPROCESS_SYMBOLS = new Set([
 66→  "exec", "execSync", "execFile", "execFileSync",
 67→  "spawn", "spawnSync", "fork",
 68→]);
 69→
 70→const VALIDATION_ERROR_PATTERNS = /Validation|Invalid|BadRequest|Forbidden|Unauthorized|NotFound/i;
 71→const RUNTIME_ERROR_TYPES = new Set(["TypeError", "ReferenceError", "SyntaxError", "RangeError", "URIError"]);
 72→
 73→/**
 74→ * Classify an error into a structured category using language-level signals.
 75→ * - validation: custom error subclasses or names suggesting deliberate input rejection
 76→ * - runtime: JS built-in error types indicating accidental failures
 77→ * - infrastructure: timeouts and system-level failures
 78→ */
 79→export function classifyError(errorType: string, message: string): ErrorCategory {
 80→  if (/timed?\s*out/i.test(message) || errorType === "ERR_SCRIPT_EXECUTION_TIMEOUT") {
 81→    return "infrastructure";
 82→  }
 83→  if (VALIDATION_ERROR_PATTERNS.test(errorType) || VALIDATION_ERROR_PATTERNS.test(message)) {
 84→    return "validation";
 85→  }
 86→  if (RUNTIME_ERROR_TYPES.has(errorType)) {
 87→    return "runtime";
 88→  }
 89→  return "unknown";
 90→}
