127→/**
128→ * Wrap a require function to intercept React module imports for .tsx files.
129→ * Non-.tsx files get the original require unchanged.
130→ */
131→function wrapRequireWithReactShim(
132→  originalRequire: NodeRequire,
133→  filePath: string | undefined,
134→): NodeRequire {
135→  if (!filePath || !filePath.endsWith(".tsx")) return originalRequire;
136→
137→  const wrapped = ((modulePath: string) => {
138→    if (REACT_MODULE_NAMES.has(modulePath)) {
139→      return getReactShim(modulePath);
140→    }
141→    return originalRequire(modulePath);
142→  }) as NodeRequire;
143→
144→  // Preserve require.resolve and require.cache for compatibility
145→  wrapped.resolve = originalRequire.resolve;
146→  wrapped.cache = originalRequire.cache;
147→  wrapped.extensions = originalRequire.extensions;
148→  wrapped.main = originalRequire.main;
149→
150→  return wrapped;
151→}
