328→/**
329→ * Truncate a message string to fit within maxBytes.
330→ * If truncated, appends a suffix indicating the message was cut.
331→ */
332→export function truncateMessage(msg: string, maxBytes: number = MESSAGE_MAX_BYTES): string {
333→  const bytes = Buffer.byteLength(msg, "utf-8");
334→  if (bytes <= maxBytes) return msg;
335→  const suffix = "…[truncated]";
336→  const suffixBytes = Buffer.byteLength(suffix, "utf-8");
337→  const target = maxBytes - suffixBytes;
338→  let end = Math.min(msg.length, target);
339→  while (Buffer.byteLength(msg.slice(0, end), "utf-8") > target && end > 0) {
340→    end--;
341→  }
342→  return msg.slice(0, end) + suffix;
343→}
344→
345→/**
346→ * Truncate console_output side effects if they exceed head+tail line limits.
347→ * Returns the (possibly truncated) effects array and truncation metadata.
348→ */
349→export function truncateSideEffects(
350→  effects: SideEffect[],
351→  headLines: number = CAPTURE_HEAD_LINES,
352→  tailLines: number = CAPTURE_TAIL_LINES,
353→): { effects: SideEffect[]; truncation?: TruncationInfo } {
354→  const consoleIndices: number[] = [];
355→  for (let i = 0; i < effects.length; i++) {
356→    const effect = effects[i];
357→    if (effect !== undefined && effect.kind === "console_output") {
358→      consoleIndices.push(i);
359→    }
360→  }
361→
362→  const consoleCount = consoleIndices.length;
363→  if (consoleCount <= headLines + tailLines) {
364→    return { effects };
365→  }
366→
367→  let originalBytes = 0;
368→  for (const idx of consoleIndices) {
369→    const e = effects[idx];
370→    if (e !== undefined && e.kind === "console_output") {
371→      originalBytes += Buffer.byteLength(e.message, "utf-8");
372→    }
373→  }
374→
375→  const keepHead = new Set(consoleIndices.slice(0, headLines));
376→  const keepTail = new Set(consoleIndices.slice(-tailLines));
377→  const truncatedCount = consoleCount - headLines - tailLines;
378→
379→  let keptBytes = 0;
380→  for (const idx of [...keepHead, ...keepTail]) {
381→    const e = effects[idx];
382→    if (e !== undefined && e.kind === "console_output") {
383→      keptBytes += Buffer.byteLength(e.message, "utf-8");
384→    }
385→  }
386→  const truncatedBytes = originalBytes - keptBytes;
387→
388→  const result: SideEffect[] = [];
389→  let markerInserted = false;
390→  for (let i = 0; i < effects.length; i++) {
391→    const effect = effects[i];
392→    if (effect === undefined) continue;
393→    if (effect.kind !== "console_output") {
394→      result.push(effect);
395→    } else if (keepHead.has(i)) {
396→      result.push(effect);
397→    } else if (keepTail.has(i)) {
398→      result.push(effect);
399→    } else if (!markerInserted) {
400→      result.push({
401→        kind: "console_output",
402→        level: "info",
403→        message: `[…truncated ${truncatedCount} lines / ${truncatedBytes} bytes…]`,
404→      });
405→      markerInserted = true;
406→    }
407→  }
408→
409→  return {
410→    effects: result,
411→    truncation: {
412→      was_truncated: true,
413→      original_lines: consoleCount,
414→      original_bytes: originalBytes,
415→    },
416→  };
417→}
418→
419→/**
420→ * Create an intercepting console that records all output as side effects.
421→ *
422→ * Captures: log, warn, error, info, debug (level mapped 1:1),
423→ * dir/table/dirxml (→ "log"), trace (→ "debug"), count/countReset (→ "log"),
424→ * time/timeEnd/timeLog (→ "log"). Non-output methods (group, clear, assert,
425→ * profile, timeStamp) delegate to the real console.
426→ */
427→function createCapturingConsole(sideEffects: SideEffect[]): Console {
428→  const makeLogger = (level: string) => (...args: unknown[]): void => {
429→    const message = truncateMessage(args.map((a) =>
430→      typeof a === "string" ? a : JSON.stringify(a) ?? String(a)
431→    ).join(" "));
432→    sideEffects.push({ kind: "console_output", level, message });
433→  };
434→
435→  const logFn = makeLogger("log");
436→  const debugFn = makeLogger("debug");
437→
438→  // Counters for console.count / console.countReset
439→  const counters = new Map<string, number>();
440→
441→  // Timers for console.time / console.timeEnd / console.timeLog
442→  const timers = new Map<string, number>();
443→
444→  return {
445→    log: logFn,
446→    warn: makeLogger("warn"),
447→    error: makeLogger("error"),
448→    info: makeLogger("info"),
449→    debug: debugFn,
450→    dir: (...args: unknown[]) => logFn(...args),
451→    table: (...args: unknown[]) => logFn(...args),
452→    dirxml: (...args: unknown[]) => logFn(...args),
453→    trace: (...args: unknown[]) => {
454→      debugFn("Trace:", ...args);
455→    },
456→    count: (label = "default") => {
457→      const n = (counters.get(label) ?? 0) + 1;
458→      counters.set(label, n);
459→      logFn(`${label}: ${n}`);
460→    },
461→    countReset: (label = "default") => {
462→      counters.set(label, 0);
463→    },
464→    time: (label = "default") => {
465→      timers.set(label, performance.now());
466→    },
467→    timeEnd: (label = "default") => {
468→      const start = timers.get(label);
469→      if (start !== undefined) {
470→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`);
471→        timers.delete(label);
472→      }
473→    },
474→    timeLog: (label = "default", ...args: unknown[]) => {
475→      const start = timers.get(label);
476→      if (start !== undefined) {
477→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`, ...args);
478→      }
479→    },
480→    assert: console.assert,
481→    clear: console.clear,
482→    group: console.group,
483→    groupCollapsed: console.groupCollapsed,
484→    groupEnd: console.groupEnd,
485→    profile: console.profile,
486→    profileEnd: console.profileEnd,
487→    timeStamp: console.timeStamp,
488→    Console: console.Console,
489→  } as unknown as Console;
490→}
491→
492→/**
493→ * Create a process-like object that intercepts stdout/stderr writes
494→ * and records them as side effects.
495→ */
496→function createCapturingProcess(sideEffects: SideEffect[]): typeof process {
497→  const makeStreamWriter = (level: string) => {
498→    const originalStream = level === "stdout" ? process.stdout : process.stderr;
499→    return new Proxy(originalStream, {
500→      get(target, prop) {
501→        if (prop === "write") {
502→          return (chunk: string | Uint8Array, ...rest: unknown[]): boolean => {
503→            const text = typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk);
504→            const trimmed = text.replace(/\n$/, "");
505→            if (trimmed.length > 0) {
506→              const message = truncateMessage(trimmed);
507→              sideEffects.push({ kind: "console_output", level, message });
508→            }
509→            return true;
510→          };
511→        }
512→        const val = Reflect.get(target, prop, target);
513→        return typeof val === "function" ? val.bind(target) : val;
514→      },
515→    });
516→  };
517→
518→  return new Proxy(process, {
519→    get(target, prop) {
520→      if (prop === "stdout") return makeStreamWriter("stdout");
521→      if (prop === "stderr") return makeStreamWriter("stderr");
522→      const val = Reflect.get(target, prop, target);
523→      return typeof val === "function" ? val.bind(target) : val;
524→    },
525→  });
526→}
527→
528→/**
529→ * Execute a function with the given inputs and capture the result.
530→ */
531→export async function executeFunction(
532→  filePath: string,
533→  functionRef: string,
534→  inputs: unknown[],
535→): Promise<RawExecuteResult> {
536→  const fn = resolveFunction(filePath, functionRef);
537→
538→  const sideEffects: SideEffect[] = [];
539→  const previousTarget = consoleTarget;
540→  consoleTarget = createCapturingConsole(sideEffects);
541→
542→  let metrics: MeasuredExecution;
543→  try {
544→    const reconstructedInputs = inputs.map(reconstructValue);
545→    metrics = await measureExecution(() => fn(...reconstructedInputs));
546→  } finally {
547→    consoleTarget = previousTarget;
548→  }
549→
550→  if (metrics.thrownError) {
551→    sideEffects.push({
552→      kind: "thrown_error",
553→      error_type: metrics.thrownError.error_type,
554→      message: metrics.thrownError.message,
555→      stack: metrics.thrownError.stack,
556→    });
557→  }
558→
559→  return {
560→    return_value: metrics.returnValue ?? null,
561→    thrown_error: metrics.thrownError,
562→    side_effects: sideEffects,
563→    branch_path: [],
564→    path_constraints: [],
565→    lines_executed: [],
566→    performance: metrics.performance,
567→    calls_to_external: [],
568→    scope_events: [],
569→    discovered_dependencies: [],
570→  };
571→}
